        self.version = version

    def on_load(self) -> None:
        print(f"Plugin {self.plugin_id} version {self.version} loaded.")

    def on_unload(self) -> None:
        print(f"Plugin {self.plugin_id} version {self.version} unloaded.")
```

2. **Utilisez IPC pour Envoyer une Reponse** :

```python
from xcore.sdk import get_service, BasePlugin

class HelloWordPlugin(BasePlugin):
    def __init__(self, plugin_id: str, version: str):
        super().__init__()
        self.plugin_id = plugin_id
        self.version = version

    def on_load(self) -> None:
        print(f"Plugin {self.plugin_id} version {self.version} loaded.")

    def on_unload(self) -> None:
        print(f"Plugin {self.plugin_id} version {self.version} unloaded.")

    def say_hello(self, name: str) -> None:
        # Envoyer une requête à l'application principale
        response = get_service("ipc").send_message({
            "type": "hello",
            "name": name
        })

        # Vérifier la réponse
        assert response.status_code in [200, 201], f"Error: {response.text}"
```

